import{_ as e,o as a,c as i,ac as t}from"./chunks/framework.DnBnwVZk.js";const k=JSON.parse('{"title":"将EasyConnect放入Docker容器运行","description":"","frontmatter":{"date":"2022-08-28T11:13:04.000Z","categories":["Linux"],"tags":["Ubuntu","网络"],"publish":true},"headers":[],"relativePath":"views/linux/net/DockerEasyConnect.md","filePath":"views/linux/net/DockerEasyConnect.md","lastUpdated":1775654397000}'),n={name:"views/linux/net/DockerEasyConnect.md"};function o(p,s,l,r,c,d){return a(),i("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1661685184000"},[...s[0]||(s[0]=[t(`<h1 id="将easyconnect放入docker容器运行" tabindex="-1">将EasyConnect放入Docker容器运行 <a class="header-anchor" href="#将easyconnect放入docker容器运行" aria-label="Permalink to &quot;将EasyConnect放入Docker容器运行&quot;">​</a></h1><p>以<a href="https://github.com/Hagb/docker-easyconnect" target="_blank" rel="noreferrer">https://github.com/Hagb/docker-easyconnect</a>仓库为基础，进行改造，首先将代码<code>git clone</code>到本地</p><h2 id="自定义编译镜像" tabindex="-1">自定义编译镜像 <a class="header-anchor" href="#自定义编译镜像" aria-label="Permalink to &quot;自定义编译镜像&quot;">​</a></h2><blockquote><p>修改镜像源</p></blockquote><p>源代码使用阿里云的debian镜像，速度相对较慢，需要改造成清华镜像源</p><ol><li><p>删除Dockerfile中<code>sed -i s/deb.debian.org/mirrors.aliyun.com/ /etc/apt/sources.list; fi</code>部分代码</p></li><li><p>代码根目录下新建sources.list文件，内容如下，注意此处使用<code>http</code>而不是s是为了省略apt update过程中的一些报错</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://mirrors.tuna.tsinghua.edu.cn/debian/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> buster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> contrib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> non-free</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://mirrors.tuna.tsinghua.edu.cn/debian/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> buster-updates</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> contrib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> non-free</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://mirrors.tuna.tsinghua.edu.cn/debian/</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> buster-backports</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> contrib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> non-free</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">deb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://mirrors.tuna.tsinghua.edu.cn/debian-security</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> buster/updates</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> contrib</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> non-free</span></span></code></pre></div></li><li><p>Dockerfile中新增一行<code>COPY sources.list /etc/apt/sources.list</code></p></li></ol><blockquote><p>修改deb包</p></blockquote><p>对于EC安装包为特制版本的，不使用源码中提供的wget方法，改为复制到源码根目录后，复制到镜像文件中</p><div class="language-docker vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">docker</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">COPY</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> EasyConnect.deb /tmp/EasyConnect.deb</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RUN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dpkg -i /tmp/EasyConnect.deb</span></span></code></pre></div><blockquote><p>编译镜像，解决问题</p></blockquote><p><code>docker image build -f Dockerfile -t docker-easyconnect .</code></p><p>问题1 安装自己的deb包出现依赖问题时，在Dockerfile的apt-get install命令后新增对应的依赖即可，对于我的情况，需要新增两个依赖包 lsb-release systemd</p><h2 id="创建运行与配置" tabindex="-1">创建运行与配置 <a class="header-anchor" href="#创建运行与配置" aria-label="Permalink to &quot;创建运行与配置&quot;">​</a></h2><blockquote><p>运行容器</p></blockquote><p><code>docker run -d --name docker-ec --device /dev/net/tun --cap-add NET_ADMIN -ti -e PASSWORD=VNC_PASS -v $HOME/.ecdata:/root -p 5901:5901 -p 1080:1080 -p 8888:8888 docker-easyconnect</code></p><p>注意上面的环境变量<code>-e PASSWORD=VNC_PASS</code>后面是指定VNC连接的密码</p><blockquote><p>配置</p></blockquote><p>使用VNC客户端连接容器，我使用的是<strong>Remmina</strong>，端口5901，密码使用上面的密码</p><p>此时容器已经准备完成</p><h2 id="常用环境配置" tabindex="-1">常用环境配置 <a class="header-anchor" href="#常用环境配置" aria-label="Permalink to &quot;常用环境配置&quot;">​</a></h2><p>对于浏览器，使用Omega进行切换，协议socks5，端口1080</p><p>对于Java程序，在RUN配置中的VM options增加选项:<code>-DsocksProxyHost=127.0.0.1 -DsocksProxyPort=1080</code><img src="https://cdn.jsdmirror.com/gh/kkyeer/picbed/20220828113953.png" alt="20220828113953"></p>`,22)])])}const u=e(n,[["render",o]]);export{k as __pageData,u as default};
